#!/usr/bin/env node
// Generates bootstrap.js — the single script that loads all eight language
// engines into an mcp-v8 runtime. Run after ./fetch-vendor.sh.
//
//   node build-bootstrap.mjs            # writes ./bootstrap.js
//   node build-bootstrap.mjs /out/path.js
//
// The generated file is plain (non-module) JavaScript so it can be sent
// through run_js as-is, snapshotted into a heap, or prepended to user code.
import { readFileSync, writeFileSync } from 'node:fs';
import { dirname, join } from 'node:path';
import { fileURLToPath } from 'node:url';

const here = dirname(fileURLToPath(import.meta.url));
const out = process.argv[2] || join(here, 'bootstrap.js');
const vendor = (name) => readFileSync(join(here, 'vendor', name), 'utf8');
const vendorBytes = (name) => readFileSync(join(here, 'vendor', name));

// ── Transforms ─────────────────────────────────────────────────────────────

// Emscripten ES6 glue (picat.mjs): strip the export, neutralize import.meta.
function transformEmscripten(src, scriptName) {
  return src
    .replace(/import\.meta\.url/g, JSON.stringify('file:///opt/languages/' + scriptName))
    .replace(/export\s+default\s+createPicat\s*;?/, '/* export stripped */');
}

// wasmoon UMD bundle (Emscripten glue + LuaFactory/LuaEngine wrappers):
// expose the internal Emscripten module factory so the helper can instantiate
// the Lua VM per call against the server-preloaded `__wasm_lua` module.
function transformWasmoon(src) {
  const out = src.replace(
    /(\n\s*exports\.decorateUserdata = decorateUserdata;)/,
    '$1\n    exports.initWasmModule = initWasmModule;');
  if (out === src) throw new Error('wasmoon transform: could not inject initWasmModule export');
  return out;
}

// wasm-bindgen glue: strip `export` keywords, neutralize import.meta, and
// append an assignment of the public surface onto the `__out` parameter the
// helper passes in (see src/helpers.js).
function transformWasmBindgen(src, scriptName, apiNames) {
  let s = src
    .replace(/import\.meta\.url/g, JSON.stringify('file:///opt/languages/' + scriptName))
    .replace(/^export\s+(function|class|const|let|var)\s/gm, '$1 ')
    .replace(/^export\s*\{[^}]*\}\s*;?\s*$/gm, '/* export stripped */')
    .replace(/^export\s+default\s+([A-Za-z_$][\w$]*)\s*;?\s*$/gm, '/* export default stripped */');
  const apiEntries = apiNames
    .map((n) => `${n}: (typeof ${n} !== 'undefined' ? ${n} : undefined)`)
    .join(', ');
  s += `\n;__out.initSync = initSync;\n__out.init = __wbg_init;\n__out.api = { ${apiEntries} };\n`;
  return s;
}

// ── Sources ────────────────────────────────────────────────────────────────

const polyfills = readFileSync(join(here, 'src', 'polyfills.js'), 'utf8');
const helpers = readFileSync(join(here, 'src', 'helpers.js'), 'utf8');
const luaWasmoon = transformWasmoon(vendor('wasmoon.js'));

const sources = {
  picat: transformEmscripten(vendor('picat.mjs'), 'picat.mjs'),
  tla: transformWasmBindgen(vendor('tla_checker.js'), 'tla_checker.js', [
    'check_spec', 'check_spec_with_cfg', 'check_spec_with_config', 'check_spec_with_options',
  ]),
  acadlisp: transformWasmBindgen(vendor('acadlisp.js'), 'acadlisp.js', ['WasmEngine']),
  mzn_worker: vendor('minizinc-worker.js'),
};

const pureJs = {
  babel: vendor('babel.min.js'),
  react: vendor('react.min.js'),
  react_dom_server: vendor('react-dom-server.min.js'),
  marked: vendor('marked.min.js'),
  mermaid: vendor('mermaid.min.js'),
};

const data = {
  minizinc_data_b64: vendorBytes('minizinc.data').toString('base64'),
};

const versions = {
  picat: '3.9#8.2 (wasm32, full engine: planner/tabling/CP/SAT)',
  tlaplus: 'tla-checker (wasm)',
  minizinc: '4.4.6 (wasm, gecode/chuffed)',
  autolisp: 'acadlisp (wasm)',
  lua: 'wasmoon 1.16 (lua 5.4, wasm)',
  jsx: 'babel-standalone 7.26 + react 18.3 (server render)',
  markdown: 'marked 11.1 (gfm)',
  mermaid: '9.4.3 (parse/validate only — no DOM)',
};

// ── Emit ───────────────────────────────────────────────────────────────────

const parts = [];
parts.push('// GENERATED by languages/build-bootstrap.mjs — do not edit.');
parts.push('// Loads picat, tla+, minizinc, autolisp, lua, jsx, markdown, mermaid into mcp-v8.');
parts.push('if (typeof globalThis.__LANG_READY === "undefined") {');
parts.push(polyfills);
parts.push(`globalThis.__LANG = { sources: ${JSON.stringify(sources)}, data: ${JSON.stringify(data)}, versions: ${JSON.stringify(versions)} };`);
// Evaluate the pure-JS engines at global scope via indirect eval (UMD
// bundles attach to globalThis; sources are dropped afterwards so heap
// snapshots keep one copy of each engine, not two).
parts.push(`globalThis.__LANG.__pure = ${JSON.stringify(pureJs)};`);
parts.push(`
(0, eval)(globalThis.__LANG.__pure.babel);
(0, eval)(globalThis.__LANG.__pure.react);
(0, eval)(globalThis.__LANG.__pure.react_dom_server);
(0, eval)(globalThis.__LANG.__pure.marked);
try {
  // mermaid's UMD body references window/navigator/location directly, but we
  // must not define a global \`window\` (Emscripten keys env detection off it),
  // so feed scoped stubs through Function parameters instead.
  const __mermaidOverrides = {
    addEventListener() {}, removeEventListener() {},
    document: globalThis.document,
    navigator: { userAgent: 'mcp-v8' },
    location: { href: 'http://localhost/', search: '' },
    matchMedia: () => ({ matches: false, addListener() {}, addEventListener() {} }),
  };
  // Proxy: explicit stubs first, everything else (Error, Promise, ...) from
  // globalThis — mermaid pokes at window.<builtin> in several places.
  const __mermaidWindow = new Proxy(__mermaidOverrides, {
    get: (t, k) => (k in t ? t[k] : globalThis[k]),
    set: (t, k, v) => { t[k] = v; return true; },
    has: () => true,
  });
  new Function('window', 'navigator', 'location', globalThis.__LANG.__pure.mermaid)(
    __mermaidWindow, __mermaidWindow.navigator, __mermaidWindow.location);
  if (globalThis.mermaid && globalThis.mermaid.initialize) {
    globalThis.mermaid.initialize({ startOnLoad: false });
  }
} catch (e) {
  globalThis.__LANG.mermaidLoadError = String(e && e.message || e);
}
delete globalThis.__LANG.__pure;
`);
// Lua (wasmoon). Evaluated once here so only the JS wrapper classes live in
// the heap; the Lua VM itself is instantiated fresh per call (see helpers.js).
parts.push(`globalThis.__LANG.__lua = ${JSON.stringify(luaWasmoon)};`);
parts.push(`
try {
  // wasmoon's Emscripten glue is an ASSERTIONS+STRICT build: it forbids the
  // instantiateWasm/print incoming-module hooks and aborts on "shell"
  // environment detection (no window/process/importScripts). Evaluate it with
  // scoped browser-ish globals so it detects a web environment, and feed the
  // Lua VM wasm through a fetch shim + a permanent instantiateStreaming
  // override that serves the server-preloaded \`__wasm_lua\` module.
  const __luaExports = {};
  const __luaDoc = { currentScript: null, baseURI: 'https://__preloaded_lua__/' };
  const __luaFetch = function (url) {
    url = String(url);
    if (url.indexOf('__preloaded_lua__') !== -1) {
      return Promise.resolve({
        ok: true, status: 200, __preloadedWasm: globalThis.__wasm_lua,
        arrayBuffer: async () => { throw new Error('lua: use instantiateStreaming'); },
      });
    }
    return globalThis.fetch ? globalThis.fetch(url) : Promise.reject(new Error('lua: unexpected fetch ' + url));
  };
  new Function(
    'window', 'location', 'document', 'navigator', 'self',
    'importScripts', 'process', 'require', 'XMLHttpRequest', 'fetch',
    'module', 'exports',
    globalThis.__LANG.__lua)(
    {}, { href: 'https://__preloaded_lua__/' }, __luaDoc, { userAgent: 'mcp-v8' }, undefined,
    undefined, undefined, undefined, undefined, __luaFetch,
    { exports: __luaExports }, __luaExports);
  if (!__luaExports || typeof __luaExports.LuaEngine !== 'function' || typeof __luaExports.initWasmModule !== 'function') {
    throw new Error('wasmoon did not expose LuaEngine/initWasmModule');
  }
  globalThis.wasmoon = __luaExports;
  // Permanent pass-through override: only special-cases the sentinel response
  // carrying a preloaded WebAssembly.Module; everything else delegates to the
  // original (and minizinc's per-call override nests cleanly on top).
  (function () {
    const orig = WebAssembly.instantiateStreaming;
    WebAssembly.instantiateStreaming = async function (resp, imports) {
      resp = await resp;
      if (resp && resp.__preloadedWasm) {
        const instance = await WebAssembly.instantiate(resp.__preloadedWasm, imports);
        return { instance, module: resp.__preloadedWasm };
      }
      if (orig) return orig.call(WebAssembly, resp, imports);
      const bytes = await resp.arrayBuffer();
      return WebAssembly.instantiate(bytes, imports);
    };
  })();
} catch (e) {
  globalThis.__LANG.luaLoadError = String(e && e.message || e);
}
delete globalThis.__LANG.__lua;
`);
parts.push(helpers);
parts.push('globalThis.__LANG_READY = true;');
parts.push('console.log("languages bootstrap loaded:", JSON.stringify(Object.keys(globalThis.__LANG.versions)));');
parts.push('} else { console.log("languages bootstrap already loaded"); }');

const code = parts.join('\n');
writeFileSync(out, code);
console.log(`wrote ${out} (${(code.length / 1024 / 1024).toFixed(2)} MB)`);
